import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Show {
  title: string;
  episodesLeft: number;
  timeToFinish: string;
}

interface WatchlistData {
  currentShow: Show;
  watchlist: Show[];
}

export default function Widget() {
  const { currentShow, watchlist } = response.data as WatchlistData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              Now Watching
            </Typography>
            <Typography variant="h5" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
              {currentShow.title}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Next: {currentShow.nextEpisode}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Episodes Left: {currentShow.episodesLeft}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Time to Finish: {currentShow.timeToFinish}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Watchlist
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {watchlist.map((show, index) => (
                <Chip
                  key={index}
                  label={`${show.title} (${show.episodesLeft} left, ${show.timeToFinish})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#424242', color: '#FFFFFF' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
